== TemplateData ==
{{TemplateData header}}
<templatedata>
{
	"params": {
		"1": {
			"label": "Title",
			"description": "Title of the article on Polish Wikipedia",
			"example": "Rzymski dyplom wojskowy",
			"type": "wiki-page-name",
			"required": true,
			"suggested": true
		},
		"date": {
			"label": "Date",
			"description": "Current date (month and year)",
			"example": "April 2016",
			"type": "date",
			"autovalue": "05 2025",
			"required": true,
			"suggested": true
		},
		"fa": {
			"label": "Featured",
			"description": "Is the article in Polish Featured (does it have Artykuł na Medal status?)",
			"example": "yes",
			"type": "boolean",
			"autovalue": "yes",
			"suggested": true
		},
		"section": {
			"label": "Section",
			"description": "If set to 'yes', emits text, 'This section...' instead of, 'This article.')",
			"example": "yes",
			"type": "boolean",
			"autovalue": "yes",
			"autovalue": ""
		},
		"topic": {
			"label": "Category",
			"description": "If set, the value of the parameter would become a name of a Category this article would be placed in. For instance setting it to \"Historical\" would place the article in the [[Category:Historical articles needing translation from Polish Wikipedia]]",
			"example": "Historical",
			"type": "content",
			"autovalue": ""
		}
	},
	"description": "Template adds a boilerplate informing that the article could be expanded using information published in the corresponding article of Polish Wikipedia.",
	"format": "block"
}
</templatedata>
</noinclude>

